export type City = {
  slug: string;
  displayName: string;
  region: string;
  regionSlug: string;

  // SEO
  title: string;
  metaTitle: string;
  metaDescription: string;
  kwPrincipal: string;
  kwSecondaires: string[];

  // Local market
  population: number;
  tourists: number;
  activeListings: number;
  priceLow: number;
  priceHigh: number;
  occupancyRate: number; // %
  revpar: number;
  seasonality: string;
  rankNational: number; // 1-10 position nationale LCD

  // Content variables
  introCustom: string;
  marketIntro: string; // 1-2 paragraphs unique to city
  conciergeries: Conciergerie[];
  neighborhoods: Neighborhood[];
  regulation: string; // Multi-paragraph
  concreteExample: {
    bienType: string;
    surface: number;
    pricePerNight: number;
    neighborhood: string;
    revenuBrut: number;
    commissionRate: number; // 0.20 for 20%
    menageCount: number;
    menageUnitCost: number;
  };
  extraFaq: CityFaq[];
  updatedAt: string; // ISO date
};

